import{_ as l,C as s,o,c as n,E as a,w as r,a as i,a0 as d}from"./chunks/framework.CkNTPv-z.js";const y=JSON.parse('{"title":"Croatia Healthcare","description":"Healthcare and HRT access for transgender people in Croatia","frontmatter":{"layout":"doc","title":"Croatia Healthcare","description":"Healthcare and HRT access for transgender people in Croatia"},"headers":[],"relativePath":"europe/croatia/healthcare.md","filePath":"europe/croatia/healthcare.md","lastUpdated":null}'),c={name:"europe/croatia/healthcare.md"};function h(p,e,u,g,m,b){const t=s("Badge");return o(),n("div",null,[a(t,{variant:"red"},{default:r(()=>[...e[0]||(e[0]=[i("Gatekeeping Model",-1)])]),_:1}),a(t,{variant:"yellow"},{default:r(()=>[...e[1]||(e[1]=[i("Limited Services",-1)])]),_:1}),e[2]||(e[2]=d('<h1 id="healthcare-in-croatia" tabindex="-1">Healthcare in Croatia <a class="header-anchor" href="#healthcare-in-croatia" aria-label="Permalink to &quot;Healthcare in Croatia&quot;">​</a></h1><h2 id="gender-affirming-healthcare" tabindex="-1">Gender Affirming Healthcare <a class="header-anchor" href="#gender-affirming-healthcare" aria-label="Permalink to &quot;Gender Affirming Healthcare&quot;">​</a></h2><p>Croatia operates a <strong>gatekeeping model</strong> for trans healthcare with very limited services. Most trans-specific care is centralised in <strong>Zagreb</strong>, with few providers outside the capital.</p><h2 id="hrt-access" tabindex="-1">HRT Access <a class="header-anchor" href="#hrt-access" aria-label="Permalink to &quot;HRT Access&quot;">​</a></h2><h3 id="requirements" tabindex="-1">Requirements <a class="header-anchor" href="#requirements" aria-label="Permalink to &quot;Requirements&quot;">​</a></h3><ul><li>Psychiatric diagnosis of gender dysphoria</li><li>Referral to an endocrinologist</li><li>Minimum assessment period before HRT</li><li>Regular follow-up appointments</li><li>Ongoing psychiatric involvement</li></ul><h3 id="process" tabindex="-1">Process <a class="header-anchor" href="#process" aria-label="Permalink to &quot;Process&quot;">​</a></h3><ol><li><strong>Psychiatric Assessment</strong> — At the University Hospital Centre Zagreb (KBC Zagreb) or a private psychiatrist with trans experience</li><li><strong>Diagnosis</strong> — Gender dysphoria diagnosis (ICD-11)</li><li><strong>Referral</strong> — To an endocrinologist for HRT</li><li><strong>HRT Initiation</strong> — Hormones prescribed after medical evaluation</li><li><strong>Monitoring</strong> — Regular blood tests and check-ups every 3-6 months</li></ol><h3 id="key-clinics" tabindex="-1">Key Clinics <a class="header-anchor" href="#key-clinics" aria-label="Permalink to &quot;Key Clinics&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Clinic</th><th>Location</th><th>Services</th><th>Wait Times</th></tr></thead><tbody><tr><td>KBC Zagreb - Psychiatric Clinic</td><td>Zagreb</td><td>Diagnosis, assessment</td><td>3-6 months</td></tr><tr><td>KBC Zagreb - Endocrinology</td><td>Zagreb</td><td>HRT, monitoring</td><td>3-6 months</td></tr><tr><td>KBC Rijeka</td><td>Rijeka</td><td>Limited trans services</td><td>4-8 months</td></tr><tr><td>KBC Split</td><td>Split</td><td>Very limited trans services</td><td>6-12 months</td></tr><tr><td>KBC Osijek</td><td>Osijek</td><td>Minimal trans services</td><td>N/A</td></tr></tbody></table><h3 id="challenges" tabindex="-1">Challenges <a class="header-anchor" href="#challenges" aria-label="Permalink to &quot;Challenges&quot;">​</a></h3><ul><li>Very few specialists with trans healthcare experience</li><li>Long waiting times for appointments</li><li>Limited availability outside Zagreb</li><li>Many healthcare professionals lack training in trans health</li><li>Language barriers (limited English in some settings)</li><li>Stigma and discrimination concerns in rural healthcare settings</li></ul><h2 id="prescription-portability" tabindex="-1">Prescription Portability <a class="header-anchor" href="#prescription-portability" aria-label="Permalink to &quot;Prescription Portability&quot;">​</a></h2><ul><li><strong>EU member</strong> — EU prescription cross-border rules apply</li><li>EU/EEA prescriptions valid for up to 30 days</li><li>Croatian Health Insurance Fund (HZZO) covers prescriptions</li><li>Non-EU prescriptions require verification</li><li>HRT medications are generally available at pharmacies</li></ul><h2 id="insurance-coverage" tabindex="-1">Insurance Coverage <a class="header-anchor" href="#insurance-coverage" aria-label="Permalink to &quot;Insurance Coverage&quot;">​</a></h2><p>Croatia has <strong>mandatory health insurance (HZZO)</strong> :</p><ul><li>Basic coverage includes trans-related care</li><li>HRT medications partially covered (prescription fee)</li><li>Surgery coverage requires medical necessity approval</li><li>Private insurance is supplemental</li><li>Out-of-pocket costs are relatively low</li></ul><h2 id="surgical-options" tabindex="-1">Surgical Options <a class="header-anchor" href="#surgical-options" aria-label="Permalink to &quot;Surgical Options&quot;">​</a></h2><ul><li>Gender-affirming surgery is available in Croatia but very limited</li><li>Most trans people travel abroad for surgery (Serbia, Thailand, Spain, Germany)</li><li>Insurance may cover partial costs of overseas surgery with prior approval</li><li>Top surgery: available in Zagreb, wait 1-2 years</li><li>Bottom surgery: very limited availability in Croatia</li><li>FFS and other surgeries: not available locally</li></ul><h2 id="mental-health-support" tabindex="-1">Mental Health Support <a class="header-anchor" href="#mental-health-support" aria-label="Permalink to &quot;Mental Health Support&quot;">​</a></h2><ul><li><strong>KBC Zagreb</strong> — Psychiatric support included in assessment</li><li><strong>TransAid Croatia</strong> — Peer support and advocacy</li><li><strong>Zagreb Pride</strong> — Community events and support</li><li><strong>LORI Rijeka</strong> — LGBTQ+ counselling</li><li>Private therapists: very few with trans experience</li></ul><h2 id="costs" tabindex="-1">Costs <a class="header-anchor" href="#costs" aria-label="Permalink to &quot;Costs&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Service</th><th>Typical Cost</th><th>Insurance Coverage</th></tr></thead><tbody><tr><td>GP visit</td><td>Covered</td><td>Full</td></tr><tr><td>Psychiatric assessment</td><td>Covered</td><td>Full</td></tr><tr><td>Endocrinology consult</td><td>Covered</td><td>Full</td></tr><tr><td>HRT (monthly)</td><td>€10-30</td><td>Partial (prescription fee)</td></tr><tr><td>Blood tests</td><td>Covered</td><td>Full</td></tr><tr><td>Private therapy</td><td>€30-60</td><td>Not covered</td></tr></tbody></table><h2 id="resources" tabindex="-1">Resources <a class="header-anchor" href="#resources" aria-label="Permalink to &quot;Resources&quot;">​</a></h2><ul><li><a href="https://www.hzzo.hr/" target="_blank" rel="noreferrer">HZZO - Croatian Health Insurance Fund</a></li><li><a href="https://www.kbc-zagreb.hr/" target="_blank" rel="noreferrer">KBC Zagreb</a></li><li><a href="https://transaid.hr/" target="_blank" rel="noreferrer">TransAid Croatia</a></li><li><a href="https://lori.hr/" target="_blank" rel="noreferrer">LORI - LGBTQ+ Association</a></li><li><a href="https://zagreb-pride.net/" target="_blank" rel="noreferrer">Zagreb Pride</a></li></ul>',25))])}const v=l(c,[["render",h]]);export{y as __pageData,v as default};
